import os
import boto3

def load_latest_model(model_path_env_var):
    # Fetch the model path from the environment variable
    model_path = os.getenv(model_path_env_var)
    if not model_path:
        raise ValueError(f"Environment variable {model_path_env_var} is not set.")

    # Extract bucket and key from the S3 path
    s3_url_parts = model_path.split('/', 3)
    bucket_name = s3_url_parts[2]
    object_key = '/'.join(s3_url_parts[3:])

    # Initialize a boto3 client for S3
    s3_client = boto3.client('s3')

    # List all versions of the object in descending order by last modified date
    response = s3_client.list_object_versions(Bucket=bucket_name, Prefix=object_key)
    if 'Versions' not in response or len(response['Versions']) == 0:
        raise ValueError(f"No versions found for model at {model_path}.")

    # Get the latest version
    latest_version = max(response['Versions'], key=lambda x: x['LastModified'])

    # Download the latest version of the model to a local file
    local_model_path = '/tmp/latest_model'
    s3_client.download_file(bucket_name, object_key, local_model_path)

    # Load the model (assuming it's a pickle file for simplicity)
    import joblib
    model = joblib.load(local_model_path)

    return model

